import os
import time
import pytest
import can

IC_MSG_ID = 0x300
GW_MSG_ID = 0x400

@pytest.fixture(scope="session")
def can_bus():
    bus = can.Bus(interface=os.getenv("CAN_INTERFACE", "socketcan"), channel=os.getenv("CAN_CHANNEL", "can0"), bitrate=500000)
    yield bus
    bus.shutdown()

def get_bit(data: bytes, bit: int) -> int:
    byte_idx = bit // 8
    bit_off = bit % 8
    return (data[byte_idx] >> bit_off) & 0x01

def wait_for_message(bus, msg_id, timeout=2.0):
    start = time.time()
    while time.time() - start < timeout:
        msg = bus.recv(timeout=0.05)
        if msg and msg.arbitration_id == msg_id:
            return msg
    raise AssertionError(f"Timeout waiting for message {hex(msg_id)}")

def collect_messages(bus, msg_id, duration):
    msgs = []
    end = time.time() + duration
    while time.time() < end:
        m = bus.recv(timeout=0.05)
        if m and m.arbitration_id == msg_id: msgs.append(m)
    return msgs

