def test_tc_hrn_005_stability_pressed(can_bus):
    msgs = collect_messages(can_bus, IC_MSG_ID, duration=5.0)
    assert all(get_bit(m.data, 0) == 1 for m in msgs)

def test_tc_hrn_006_stability_released(can_bus):
    msgs = collect_messages(can_bus, IC_MSG_ID, duration=5.0)
    assert all(get_bit(m.data, 0) == 0 for m in msgs)

def test_tc_hrn_007_no_invalid_values(can_bus):
    msgs = collect_messages(can_bus, IC_MSG_ID, duration=3.0)
    assert all(get_bit(m.data, 0) in (0, 1) for m in msgs)
